(3, 32, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ভিডিও ৩', NULL, NULL, NULL, NULL, 'অনলাইন ডেস্ক', NULL, '<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/2ZxzQ0EP4wQ?si=7ZJaenwK76PnpAoZ&amp;controls=0\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>', NULL, 'ভিডিও', NULL, NULL, NULL, NULL, NULL, 'ভিডিও ৩', 'ভিডিও ৩', 'ভিডিও', 1, NULL, NULL, NULL, 0, 3, NULL, 5, '2024-10-30 07:55:06', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 2, '2024-10-27 18:34:21', 2, '2024-11-04 06:22:44'),
(4, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'সৈয়দা রিজওয়ানা হাসান', 'সরকারি খরচে কাউকে হজে পাঠানো হবে না', NULL, NULL, NULL, NULL, 'বাংলাদেশের প্রতিবেদক', NULL, NULL, NULL, 'হজ,সরকারি খরচে হজ,হজের খরচ', NULL, 'HAJJ-671fb428af58f-671fcd57bea01.jpg', NULL, '', NULL, 'এ বছর সরকারি খরচে কাউকে হজে পাঠানো হবে না। কেবল হজ ব্যবস্থাপনার দায়িত্বে নিয়োজিত ব্যক্তিরা যাবেন।', 'এ বছর সরকারি খরচে কাউকে হজে পাঠানো হবে না। কেবল হজ ব্যবস্থাপনার দায়িত্বে নিয়োজিত ব্যক্তিরা যাবেন।', 'হজ,সরকারি খরচে হজ,হজের খরচ', 1, NULL, NULL, NULL, 0, 4, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 4, '2024-10-28 15:56:24', 5, '2024-10-29 06:34:20'),
(5, 25, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'সাহিত্যে নোবেল পেলেন দক্ষিণ কোরিয়ার হ্যান কাং', NULL, NULL, NULL, NULL, 'বাসস', NULL, NULL, NULL, 'নোবেল পুরস্কার,হ্যান কাং', NULL, 'Hankong-671fc94ca3e48-671fcf02e010c.jpg', NULL, '', NULL, 'এবার সাহিত্যে নোবেল পুরস্কার জিতেছেন দক্ষিণ কোরিয়ার ছোট গল্পকার ও ঔপন্যাসিক হ্যান কাং। বৃহস্পতিবার (১০ অক্টোবর) সুইডেনের রাজধানী স্টকহোমে রয়্যাল সুইডিশ একাডেমি', 'এবার সাহিত্যে নোবেল পুরস্কার জিতেছেন দক্ষিণ কোরিয়ার ছোট গল্পকার ও ঔপন্যাসিক হ্যান কাং। বৃহস্পতিবার (১০ অক্টোবর) সুইডেনের রাজধানী স্টকহোমে রয়্যাল সুইডিশ একাডেমি', 'নোবেল পুরস্কার,হ্যান কাং', 1, NULL, NULL, NULL, 0, 7, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 4, '2024-10-28 17:26:36', 5, '2024-10-29 06:34:20'),
(6, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'আন্দোলনের মুখে ঢাকা বোর্ড চেয়ারম্যানের পদত্যাগের ঘোষণা', NULL, NULL, NULL, NULL, 'বাংলাদেশের প্রতিবেদক', NULL, NULL, NULL, 'পদত্যাগ', NULL, 'Tapon-671fd7278130a-671fec8a02c89.jpg', NULL, '', NULL, 'এইচএসসিতে অকৃতকার্য হওয়া একদল শিক্ষার্থীর অটোপাসের দাবির মুখে পদত্যাগের ঘোষণা দিয়েছেন ঢাকা শিক্ষাবোর্ডের চেয়ারম্যান অধ্যাপক তপন কুমার সরকার।', 'এইচএসসিতে অকৃতকার্য হওয়া একদল শিক্ষার্থীর অটোপাসের দাবির মুখে পদত্যাগের ঘোষণা দিয়েছেন ঢাকা শিক্ষাবোর্ডের চেয়ারম্যান অধ্যাপক তপন কুমার সরকার।', 'পদত্যাগ', 1, NULL, NULL, NULL, 0, 5, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 4, '2024-10-28 18:25:43', 5, '2024-10-29 06:34:20'),
(7, 12, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ফরিদপুরে দুই বাসের মুখোমুখি সংঘর্ষে নিহত ৫', NULL, NULL, NULL, NULL, 'ফরিদপুর প্রতিনিধি', NULL, NULL, NULL, 'সড়ক দুর্ঘটনা,ফরিদপুর,নিহত', NULL, 'Accident-Faridpur-671fe03ad6a00-671febbbd2663.jpg', NULL, '', NULL, 'ফরিদপুর-খুলনা মহাসড়কের মল্লিকপুরে দুই বাসের মুখোমুখি সংঘর্ষে পাঁচজন নিহত হয়েছেন। এ ঘটনায় বেশ কয়েকজন আহত হয়েছেন।', 'ফরিদপুর-খুলনা মহাসড়কের মল্লিকপুরে দুই বাসের মুখোমুখি সংঘর্ষে পাঁচজন নিহত হয়েছেন। এ ঘটনায় বেশ কয়েকজন আহত হয়েছেন।', 'সড়ক দুর্ঘটনা,ফরিদপুর,নিহত', 1, 2, 21, 220, 0, 6, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 4, '2024-10-28 19:04:26', 5, '2024-10-29 06:34:20'),
(8, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'বিশেষ অভিযান জোরদারের নির্দেশ আইজিপির', NULL, NULL, NULL, NULL, 'বাংলাদেশের ডেস্ক', NULL, NULL, NULL, 'পুলিশ ,আইজিপি,অভিযান,গ্রেপ্তার ,ডিএমপি', NULL, 'bangladesherKhabor-67204ce62e3cb.jpg', NULL, '', NULL, 'নানা অপরাধের বিরুদ্ধে চলমান বিশেষ অভিযান জোরদার করতে পুলিশের সকল ইউনিট প্রধানদের প্রতি নির্দেশ দিয়েছেন পুলিশের মহাপরিদর্শক (আইজিপি) মো. ময়নুল ইসলাম...', 'নানা অপরাধের বিরুদ্ধে চলমান বিশেষ অভিযান জোরদার করতে পুলিশের সকল ইউনিট প্রধানদের প্রতি নির্দেশ দিয়েছেন পুলিশের মহাপরিদর্শক (আইজিপি) মো. ময়নুল ইসলাম...', 'পুলিশ ,আইজিপি,অভিযান,গ্রেপ্তার ,ডিএমপি', 1, NULL, NULL, NULL, 0, 8, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 5, '2024-10-29 02:43:44', 5, '2024-10-29 06:34:20'),
(9, 34, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'রদ্রিই জিতলেন ব্যালন ডি’অর', NULL, NULL, NULL, NULL, 'স্পোর্টস ডেস্ক', NULL, NULL, NULL, 'ব্যালন ডি’অর,ফুটবল,রদ্রিগো হার্নান্দেজ', NULL, 'bangladesherKhabor1-672063ac95f9e.jpg', NULL, '', NULL, '২০২৪ সালের ব্যালন ডি\'অর জিতলেন ম্যানচেস্টার সিটির স্প্যানিশ তারকা রদ্রিগো হার্নান্দেজ...', '২০২৪ সালের ব্যালন ডি\'অর জিতলেন ম্যানচেস্টার সিটির স্প্যানিশ তারকা রদ্রিগো হার্নান্দেজ...', 'ব্যালন ডি’অর,ফুটবল,রদ্রিগো হার্নান্দেজ', 1, NULL, NULL, NULL, 0, 9, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 5, '2024-10-29 04:25:16', 5, '2024-10-29 06:34:20'),
(10, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'গণভবন জাদুঘর', '‘আয়নাঘরের রেপ্লিকা’ রাখার নির্দেশ প্রধান উপদেষ্টার', NULL, NULL, NULL, NULL, 'বাংলাদেশের ডেস্ক', NULL, NULL, NULL, 'ড. মুহাম্মদ ইউনূস,অন্তর্বর্তী সরকার,গণভবন,আওয়ামী লীগ,শেখ হাসিনা', NULL, 'bangladesherKhabor2-672066edbd50f.jpg', NULL, '', NULL, 'গত ১৫ বছরে ফ্যাসিবাদি সরকারের নির্মম নির্যাতনের বার্তা ভবিষ্যত প্রজন্মের কাছে পৌঁছে দিতে গণভবন জাদুঘরে ‘আয়নাঘরের রেপ্লিকা’ রাখার নির্দেশ দিয়েছেন ড. ইউনূস...', 'গত ১৫ বছরে ফ্যাসিবাদি সরকারের নির্মম নির্যাতনের বার্তা ভবিষ্যত প্রজন্মের কাছে পৌঁছে দিতে গণভবন জাদুঘরে ‘আয়নাঘরের রেপ্লিকা’ রাখার নির্দেশ দিয়েছেন ড. ইউনূস...', 'ড. মুহাম্মদ ইউনূস,অন্তর্বর্তী সরকার,গণভবন,আওয়ামী লীগ,শেখ হাসিনা', 1, NULL, NULL, NULL, 0, 10, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 5, '2024-10-29 04:36:27', 5, '2024-10-29 06:34:20');
