INSERT INTO `article_details` (`id`, `article_id`, `body`) VALUES
(1, 1, NULL),
(2, 2, NULL),
(3, 3, NULL),
(8, 5, '<p>এবার সাহিত্যে নোবেল পুরস্কার জিতেছেন দক্ষিণ কোরিয়ার ছোট গল্পকার ও ঔপন্যাসিক হ্যান কাং। বৃহস্পতিবার (১০ অক্টোবর) সুইডেনের রাজধানী স্টকহোমে রয়্যাল সুইডিশ একাডেমি অব সায়েন্সের স্থায়ী সচিব ম্যাটস মাম ২০২৪ সালে সাহিত্যে নোবেল পুরস্কার বিজয়ীর নাম ঘোষণা করেন।</p><p>তাকে পুরস্কার প্রদানের কারণ হিসেবে বলা হয়, ‘তার ঐকান্তিক কাব্যিক গদ্য ঐতিহাসিক মর্মাঘাত সামনে আনে এবং মানবজীবনের ভঙ্গুরতা উন্মোচন করে দেখায়।’</p><p>হ্যান কাং ১৯৭০ সালে দক্ষিণ কোরিয়ার শহর গোয়াংজুতে জন্মগ্রহণ করেন। নয় বছর বয়সে পরিবারের সঙ্গে সিউলে চলে আসেন। তিনি একটি সাহিত্যিক পরিবেশে জন্ম নেন। তার বাবাও একজন স্বনামধন্য ঔপন্যাসিক। লেখালেখির পাশাপাশি তিনি নিজেকে শিল্প ও সংগীতেও নিয়োজিত করেছেন।&nbsp;</p><p>এর আগের বছর ২০২৩ সালে সাহিত্যে নোবেল পুরস্কার পান নরওয়ের লেখক ও নাট্যকার ইয়োন ফসে। ১৯০১ সালে সাহিত্যে প্রথম নোবেল পুরস্কার পান ফরাসি কবি ও প্রাবন্ধিক সুলি প্রুদোম (১৮৩৯-১৯০৭)।</p><p>এমএইচএস/এইচকে</p>'),
(9, 4, '<p>এ বছর সরকারি খরচে কাউকে হজে না পাঠানোর সিদ্ধান্ত নিয়েছে সরকার। বৃহস্পতিবার অন্তর্বর্তী সরকারের উপদেষ্টা পরিষদের বৈঠকে এ সিদ্ধান্ত নেওয়া হয়েছে।</p><p>বৈঠক শেষে রাজধানীর ফরেন সার্ভিস একাডেমিতে এক প্রেস ব্রিফিংয়ে পরিবেশ, বন ও জলবায়ু পরিবর্তন এবং পানি সম্পদ মন্ত্রণালয়ের উপদেষ্টা সৈয়দা রিজওয়ানা হাসান এ কথা জানান।</p><p>তিনি বলেন, এ বছর কেউ সরকারি অর্থে হজে যাবেন না। হজ ব্যবস্থাপনার জন্য যাদের যেতে হয় কেবল তারা যাবেন। হজের ব্যয় কমানোর চেষ্টা করা হচ্ছে। যতটা সম্ভব চেষ্টা করা হচ্ছে। হজের প্যাকেজ এই মাসের শেষেই ঘোষিত হবে। তখন আপনারা দেখতে পারবেন আমরা কতটা কমিয়েছি।</p><p>সৈয়দা রিজওয়ানা হাসান&nbsp; বলেন, হজ নিয়ে আমাদের ব্যবস্থাপনা সৌদির ব্যবস্থাপনা সবকিছু মিলিয়ে করতে হয়। সেহেতু ৩০ তারিখ পর্যন্ত আমাদের অপেক্ষা করতে হবে।</p><p>বিফ্রিংয়ে উপস্থিত ছিলেন প্রধান উপদেষ্টার বিশেষ সহকারী মাহফুজ আলম, প্রেস সচিব শফিকুল আলম প্রমুখ।</p>');
