(1, 0, 'জাতীয়', 'national', NULL, 1, 1, 'জাতীয় | National News, Breaking News BD  | বাংলাদেশের জাতীয় খবর', 'বাংলাদেশের জাতীয় খবর ও ব্রেকিং নিউজের সর্বশেষ আপডেট। রাজনীতি, সরকার, সংসদ, আইন-শৃঙ্খলা ও দেশের গুরুত্বপূর্ণ ঘটনাবলী পড়ুন নির্ভরযোগ্য সূত্রে।', 'আজকের জাতীয় খবর, Bangladesh National News, BD Breaking News, বাংলাদেশের জাতীয় খবর, জাতীয় সংবাদ, ব্রেকিং নিউজ বাংলাদেশ, বাংলাদেশের রাজনীতি, সরকারী খবর, সংসদের খবর, আইন শৃঙ্খলার খবর, দেশের খবর', NULL, 'online', NULL, 1, 1, 2, '2024-10-24 19:27:58', 19, '2026-01-23 14:30:36'),
(2, 0, 'শিক্ষা', 'education', NULL, 1, 1, 'দৈনিক শিক্ষা সংবাদ | Education News | বাংলাদেশের খবর', 'আজকের শিক্ষার সংবাদ ,প্রাইমারি, মাধ্যমিক ও উচ্চ মাধ্যমিক শিক্ষা , স্কুল–কলেজ–বিশ্ববিদ্যালয় আপডেট, ভর্তি পরীক্ষা, বৃত্তি, উচ্চশিক্ষা, শিক্ষা বার্তা বিষয়ক বিশ্লেষণ পড়ুন এখানে।', 'শিক্ষা সংবাদ, education news bangladesh, শিক্ষা খবর, exam result bd, school college university news, admission news bd', NULL, 'online', NULL, 3, 1, 2, '2024-10-24 19:28:13', 19, '2026-01-24 19:48:01'),
(3, 0, 'আইন ও বিচার', 'law-justice', NULL, 0, 1, 'আইন ও বিচার | Law & Justice News Bangladesh', 'আইন-আদালত সম্পর্কিত সর্বশেষ খবর, দেশের এবং আন্তর্জাতিক আদালতের সংবাদ, রায়, মামলা, এবং আইনগত বিশ্লেষণ সম্পর্কে আপডেট পেতে সাথে থাকুন।', 'আইন ও বিচার, law justice news bangladesh, legal news bd, courtroom updates, judicial news bangladesh, legal analysis news', NULL, 'online', NULL, 1, 1, 2, '2024-10-24 19:28:27', 19, '2026-01-24 20:36:12'),
(4, 0, 'স্বাস্থ্য', 'health', NULL, 1, 1, 'স্বাস্থ্য তথ্য: রোগ প্রতিরোধ ও সঠিক যত্নের সেরা পরামর্শ', 'স্বাস্থ্য তথ্য রোগ প্রতিরোধ, সঠিক খাদ্যাভ্যাস, স্বাস্থ্য টিপস ও চিকিৎসা পরামর্শের সর্বশেষ আপডেট', 'স্বাস্থ্য সংবাদ, health news bangladesh, চিকিৎসা সংবাদ, medical updates bd, স্বাস্থ্য টিপস, wellness tips bangladesh', NULL, 'online', NULL, 1, 1, 2, '2024-10-24 19:32:26', 19, '2026-01-25 20:29:59'),
