INSERT INTO `live_updates` (`id`, `article_id`, `title`, `image`, `image_caption`, `body`, `order_id`, `status`, `created_by`, `created_at`, `updated_by`, `updated_at`) VALUES
(1, 20459, 'রাজধানীতে থেমে থেমে বৃষ্টি, সড়কে ভোগান্তি', NULL, NULL, '<p>রাজধানী ঢাকায় সকাল থেকেই থেমে থেমে বৃষ্টি হচ্ছে। এতে ভোগান্তিতে পড়েছেন অফিসগামী মানুষ, শিক্ষার্থী ও সাধারণ পথচারীরা। বৃষ্টির সঙ্গে পরিবহন সংকট, যানজট, জলাবদ্ধতা আর কাদায় ভরা সড়ক—সব মিলিয়ে নগরজীবন একপ্রকার অচল হয়ে পড়েছে।</p>', 1, -1, 1, '2025-06-18 21:46:51', 1, '2025-06-18 21:48:35'),
(2, 20882, 'কাতারে মার্কিন ঘাঁটিতে প্রবেশ সীমিত, নাগরিকদের সতর্ক থাকার আহ্বান', NULL, NULL, '<p>মধ্যপ্রাচ্যে চলমান উত্তেজনাপূর্ণ পরিস্থিতির প্রেক্ষাপটে কাতারে অবস্থিত যুক্তরাষ্ট্রের বৃহত্তম সামরিক ঘাঁটি আল-উদেইদ এয়ার বেসে প্রবেশ সীমিত করেছে দেশটির দূতাবাস।</p><p>সম্প্রতি এক বিজ্ঞপ্তিতে মার্কিন দূতাবাস জানায়, ‘সতর্কতামূলক ব্যবস্থা’ হিসেবে তারা ঘাঁটিতে কর্মরত মার্কিন নাগরিকদের চলাচলে কিছু সীমাবদ্ধতা আরোপ করেছে। সেই সঙ্গে কাতারে অবস্থানরত সকল মার্কিন নাগরিককে বাড়তি সতর্কতা অবলম্বনের পরামর্শ দেওয়া হয়েছে। খবর আল জাজিরার।</p><p>উল্লেখ্য, কাতারের আল-উদেইদ ঘাঁটিটি মধ্যপ্রাচ্যে যুক্তরাষ্ট্রের সবচেয়ে বড় এবং গুরুত্বপূর্ণ সামরিক ঘাঁটি হিসেবে বিবেচিত। এখান থেকেই মার্কিন সেনাবাহিনী আকাশপথে পরিচালিত বিভিন্ন অভিযানের কৌশল নির্ধারণ করে থাকে।</p><div><br></div>', 2, -1, 7, '2025-06-19 12:00:19', 5, '2025-06-23 18:16:36'),
(3, 20882, 'ইরানের ‘আরাক হেভি ওয়াটার রিঅ্যাক্টরে’ ইসরাইলের হামলা', NULL, NULL, '<p><b>ইরানের ‘আরাক হেভি ওয়াটার রিঅ্যাক্টর’ পারমাণবিক স্থাপনায় হামলা চালিয়েছে ইসরায়েল। বৃহস্পতিবার (১৯ জুন) ইরানি গণমাধ্যমের বরাতে এ খবর জানিয়েছে সংবাদ সংস্থা রয়টার্স।</b></p><p>এর আগে ইসরাইলি সেনাবাহিনী হুমকি দিয়েছিল, ওই রিঅ্যাক্টরের আশপাশের এলাকার বাসিন্দারা যেন অবিলম্বে এলাকাটি ত্যাগ করেন।</p><p>এদিকে বৃহস্পতিবার (১৯ জুন) সকালে ইসরায়েলকে লক্ষ্য করে ইরানি ক্ষেপণাস্ত্রের একটি নতুন বহর নিক্ষেপ করার পরপরই জেরুজালেম এবং তেল আবিবে বেশ কয়েকটি বিস্ফোরণের শব্দ শোনা গেছে।</p><p>আল জাজিরা জানিয়েছে, এ হামলার পর মধ্য থেকে উত্তর ইসরায়েলে ‘এয়ার অ্যালার্ট’ জারি করা হয়েছে।</p><p>&nbsp;</p>', 3, -1, 7, '2025-06-19 12:26:59', 5, '2025-06-23 18:14:51'),
(4, 20856, 'ইরান-ইসরায়েল সংঘাত নিয়ে জরুরি বৈঠকে বসছে নিরাপত্তা পরিষদ', '1750316484-6853b5c48195c.jpg', NULL, '<p>ইসরায়েল ও ইরানের মধ্যে চলমান উত্তেজনা নিয়ে জাতিসংঘ নিরাপত্তা পরিষদ জরুরি বৈঠকে বসছে। স্থানীয় সময় শুক্রবার (২০ জুন) সকাল ১০টায় এ বৈঠক শুরু হবে।</p><p>এর আগে ইরান জাতিসংঘকে দেওয়া এক চিঠিতে জানায়, সংঘাত বিপজ্জনকভাবে বেড়ে গেছে এবং এতে যুক্তরাষ্ট্রের প্রত্যক্ষ অংশগ্রহণের ‘ক্রমবর্ধমান ও অনস্বীকার্য প্রমাণ’ রয়েছে। এই অভিযোগ তুলে ইরান জরুরি বৈঠকের অনুরোধ জানায়। ইরানের এই অনুরোধ সমর্থন করেছে রাশিয়া, চীন, পাকিস্তান ও আলজেরিয়া।</p><p>ইরানের দাবি, যুক্তরাষ্ট্র শুধু ইসরায়েলকে সামরিক সহায়তাই দিচ্ছে না, বরং ইরানি ভূখণ্ডে হামলার পরিকল্পনাতেও যুক্ত রয়েছে। তাই বিষয়টি নিয়ে এখন আন্তর্জাতিক পর্যায়ে আনুষ্ঠানিক আলোচনার প্রয়োজন দেখা দিয়েছে।&nbsp;</p>', 4, -1, 4, '2025-06-19 13:01:24', 4, '2025-06-19 13:12:59'),
