INSERT INTO `settings_general` (`id`, `newspaper_name`, `newspaper_name_bn`, `brand_color`, `hover_color`, `logo_1`, `logo_2`, `icon_1`, `icon_2`, `default_img_1`, `default_img_2`, `sticker`, `editor`, `publisher`, `online_head`, `mobile`, `email`, `footer`, `address`, `about`, `contact`, `privacy`, `terms`, `advertisement`, `show_topnews`, `show_selected2`, `show_live`, `updated_at`, `updated_by`) VALUES
(1, 'Bangladesher Khabor', 'বাংলাদেশের খবর', '#017AC3', '', 'BK-NEW-LOGO-BLACKlogo-1-1761163905.png', 'BK-Logo-New-whitelogo-2-1761163905.png', 'favicon.png	', 'ezgif-7-c58f72a6c2icon-2-1730277221.png', 'bk-defaultdefault-img-1-1761201123.jpg', 'bk-defaultdefault-img-2-1761201123.jpg', NULL, '<span class=\"borderC1B1 fontBold  xs-colorBlackLight xs-title1_1\">ভারপ্রাপ্ত সম্পাদক</span> <span class=\"displayBlock marginT5 xs-marginT0 xs-title1_1\">সৈয়দ মেজবাহ উদ্দিন</span>', '<span class=\"borderC1B1 fontBold  xs-colorBlackLight xs-title1_1\">সম্পাদকমণ্ডলীর সভাপতি</span> <span class=\"displayBlock marginT5 xs-marginT0 xs-title1_1\">মোস্তফা কামাল মহীউদ্দীন</span>', '<span class=\"borderC1B1 fontBold  xs-colorBlackLight xs-title1_1\">প্রধান, ডিজিটাল সংস্করণ</span> <span class=\"displayBlock marginT5 xs-marginT0 xs-title1_1\">হাসনাত কাদীর</span>', '01322-853970', 'bkdigital247@gmail.com', '<p><b>বার্তা ও বাণিজ্যিক কার্যালয় :</b> প্লট নং-৩১৪/এ, রোড-১৮, ব্লক-ই, বসুন্ধরা আ/এ, ঢাকা-১২২৯। পিএবিএক্স : ৫৫০৩৬৪৫৬-৭, ৫৫০৩৬৪৫৮, ফ্যাক্স : ৮৪৩১০৯৩,&nbsp;ইমেইল : bkdigital247@gmail.com</p><p><b>প্রিন্ট সংস্করণে বিজ্ঞাপন দিতে যোগাযোগ :</b> ০১৮৪৭-০৯১১৩১, ০১৭৩০-৭৯৩৪৭৮, ০১৮৪৭-৪২১১৫৩, ০১৩২২-৯১০৪২২, ইমেইল : bkhaboradvt2021@gmail.com</p><p><b>ডিজিটাল সংস্করণে (ওয়েবসাইট &amp; ভিডিও) বিজ্ঞাপন দিতে যোগাযোগ :</b>&nbsp;০১৭৩০-৭৯৩৪৯২ (সকাল ৯টা থেকে রাত ৯টা), ইমেইল :&nbsp;businessbk247@gmail.com</p><p><b>সার্কুলেশন :</b>&nbsp;০১৮৪৭-৪২১১৫২</p>', 'Plot No. 314/A, Road 18, Block E, Bashundhara A/A, Dhaka 1229', '<p>বাংলাদেশের খবরের আত্মপ্রকাশ ২০১৪ সালে। দেশের খবর, দশের কাছে পৌঁছে দেওয়ার লক্ষ্য নিয়ে বস্তুনিষ্ঠ, স্বাধীন ও রাজনৈতিক দলনিরপেক্ষ থেকে গণমানুষের কণ্ঠস্বর হয়ে সত্যিকারের গণমাধ্যম হিসেবে এক দশকের বেশি সময় ধরে নিরলসভাবে কাজ করে যাচ্ছে <a href=\"https://epaper.bangladesherkhabor.net/\" target=\"_blank\">দৈনিক পত্রিকাটি</a>।&nbsp;</p><p>প্রতিষ্ঠার শুরু থেকেই জনগণের পাশে থেকে সত্য, ন্যায় ও দায়বদ্ধ সাংবাদিকতাকে মূল উদ্দেশ্য হিসেবে গ্রহণ করেছে বাংলাদেশের খবর। সময়ের সঙ্গে সঙ্গে পত্রিকাটির সাংবাদিকতার ভঙ্গি আরও পরিণত হয়েছে। অনুসন্ধানী প্রতিবেদন, মানসম্মত সংবাদ পরিবেশন ও সমাজসচেতন সম্পাদকীয়র মাধ্যমে পাঠকের আস্থা অর্জন করেছে দৈনিকটি। দেশের প্রত্যন্ত অঞ্চলের খবর উপস্থাপনের লক্ষ্যে বাংলাদেশের খবরের স্থানীয় প্রতিনিধি ও কর্মীরা মাঠপর্যায়ে নিবেদিতভাবে কাজ করে যাচ্ছেন।</p><p><b>উদ্দেশ্য ও লক্ষ্য</b></p><p>বাংলাদেশের খবরের মূল লক্ষ্য হলো- জনসাধারণকে সময়োপযোগী, নিরপেক্ষ ও নির্ভুল তথ্য সরবরাহ করা। সংবাদ পৌঁছে দেওয়ার গতি আমাদের কাছে গুরুত্বপূর্ণ হলেও সেই গতিকে কখনও সত্য ও যাচাইয়ের বিপরীতে স্থান দেওয়া হয় না। আমরা স্বাধীনতা, গণতন্ত্র, ধর্মনিরপেক্ষতা ও জাতীয় সার্বভৌমত্বে বিশ্বাস করি এবং দেশের সংবিধানের মূলনীতি ও আইনকে মেনে চলি। পাঠককে তথ্যবহুল ও সচেতন নাগরিক হিসেবে গড়ে তোলা, জনমত গঠনে অবদান রাখা এবং ন্যায়ভিত্তিক সমাজ প্রতিষ্ঠায় সাংবাদিকতার শক্তিকে কাজে লাগানোই আমাদের অঙ্গীকার।</p><p><b>ডিজিটাল অভিযাত্রা</b></p><p>২০২৪ সালের ২৪ সেপ্টেম্বর বাংলাদেশের খবর ডিজিটাল সংস্করণের আনুষ্ঠানিক যাত্রা শুরু হয়। অনলাইন প্ল্যাটফর্মে আমরা শুধু সংবাদ পরিবেশনেই সীমাবদ্ধ নই; নির্ভুল, ব্যাখ্যামূলক ও গল্পনির্ভর প্রতিবেদনের সঙ্গে ছবি, ভিডিও, ইনফোগ্রাফিক ও ওয়েবস্টোরির মাধ্যমে সংবাদকে আরও জীবন্ত করে তুলি। দ্রুত আপডেট, বহুমাধ্যম উপস্থাপনা ও মতপ্রকাশের স্বাধীনতা— এসব বৈশিষ্ট্য বাংলাদেশের খবরের ডিজিটাল সংস্করণকে একটি আধুনিক, নির্ভরযোগ্য ও দায়িত্বশীল সংবাদমাধ্যম হিসেবে আলাদা পরিচিতি দিয়েছে।</p><p><b>সাংবাদিকতার মান ও নৈতিকতা</b></p><p>বাংলাদেশের খবর সর্বোচ্চ নৈতিক মান বজায় রেখে কাজ করে। আমাদের প্রতিটি প্রতিবেদনে নিরপেক্ষতা, সততা ও ন্যায়নিষ্ঠা মৌলিক শর্ত। কোনো রাজনৈতিক দল, বাণিজ্যিক প্রতিষ্ঠান বা ব্যক্তিগত স্বার্থ আমাদের সংবাদ নীতিকে প্রভাবিত করে না। মানবাধিকার, লিঙ্গসমতা, মতপ্রকাশের স্বাধীনতা ও সংবাদমাধ্যমের স্বাধীনতা— এসব বিষয়ে আমরা অকপট ও দৃঢ় অবস্থানে বিশ্বাস করি। কঠোর পেশাদারিত্ব ও দায়িত্বশীলতার মাধ্যমে পাঠকের আস্থা অটুট রাখাই আমাদের লক্ষ্য।</p><p><b>ফ্যাক্ট-চেকিং নীতি</b></p><p>তথ্য যাচাই বাংলাদেশের খবরের সম্পাদনাগত কাজের কেন্দ্রবিন্দু। কোনো খবর প্রকাশের আগে তা একাধিক উৎস থেকে যাচাই করা হয়। প্রতিবেদনে উল্লিখিত প্রত্যেক পক্ষের বক্তব্য গ্রহণ বাধ্যতামূলক এবং প্রয়োজনে সরকারি নথি, অফিসিয়াল বিবৃতি বা নির্ভরযোগ্য তৃতীয় পক্ষের তথ্য ব্যবহার করে সত্যতা নিশ্চিত করা হয়। দেশের ৬৪ জেলায় বিস্তৃত আমাদের প্রতিনিধি নেটওয়ার্ক স্থানীয়ভাবে তথ্য যাচাই ও সংগ্রহে গুরুত্বপূর্ণ ভূমিকা রাখে। সংবেদনশীল বা জটিল বিষয়ের ক্ষেত্রে সম্পাদকীয় বোর্ড পর্যবেক্ষণ করে এবং অতিরিক্ত যাচাই প্রক্রিয়া সম্পন্ন হওয়ার পরেই প্রকাশ অনুমোদন দেয়।</p><p><b>সংশোধন নীতি</b></p><p>ভুল বা ত্রুটিপূর্ণ তথ্য অনিচ্ছাকৃতভাবে প্রকাশিত হলে আমরা তা দ্রুত স্বীকার করি এবং পাঠকের প্রতি পূর্ণ স্বচ্ছতা বজায় রেখে সংশোধন প্রকাশ করি। ত্রুটির প্রকৃতি ও গুরুত্ব অনুযায়ী সংশোধনী স্পষ্টভাবে ওয়েবসাইটে প্রদর্শিত হয়, যাতে পাঠক সহজে বুঝতে পারেন কোন অংশে পরিবর্তন আনা হয়েছে। বড় ধরনের ত্রুটি বা বিভ্রান্তির ক্ষেত্রে আমরা ব্যাখ্যা-সংযুক্ত সংশোধন প্রকাশ করি এবং পাঠকের কাছে দুঃখপ্রকাশ করাকেও সাংবাদিকতার নৈতিক দায়িত্ব হিসেবে দেখি।</p><p><b>সংগঠন কাঠামো ও কাজের ধারা</b></p><p>বাংলাদেশের খবর পরিচালিত হয় একটি পেশাদার ও সুসংগঠিত সম্পাদকীয় টিমের মাধ্যমে। ভারপ্রাপ্ত সম্পাদক সামগ্রিক সম্পাদকীয় নীতি ও কনটেন্টের দিকনির্দেশনা নির্ধারণ করেন। তাঁকে সহায়তা করেন প্রধান প্রতিবেদক ও বার্তা সম্পাদক। জাতীয়, রাজনীতি, অর্থনীতি, আন্তর্জাতিক, সারাদেশ, খেলাধুলা, বিনোদন, প্রযুক্তি, শিক্ষা, সংস্কৃতি ও মতামত— প্রতিটি বিভাগ নির্দিষ্ট ইনচার্জের তত্ত্বাবধানে কাজ করে, যেখানে সিনিয়র সাব-এডিটররা প্রতিবেদন সম্পাদনা ও ভাষা পরিমার্জনের দায়িত্ব পালন করেন। গবেষণা ও উন্নয়ন বিভাগ সম্পাদকীয় পরিকল্পনা, তথ্যবিশ্লেষণ ও কলাম সংগ্রহে ভূমিকা রাখে। প্রশাসন ও মানবসম্পদ বিভাগ আর্থিক, প্রশাসনিক ও উৎপাদনসংক্রান্ত কার্যক্রম পরিচালনা করে।</p><p><b>মালিকানা, পৃষ্ঠপোষকতা ও স্বাধীনতা</b></p><p>বাংলাদেশের খবর প্রকাশিত ও পরিচালিত হয় দেশের প্রাচীন ব্যবসায়ী পরিবার <a href=\"https://maguragroup.com.bd/\" target=\"_blank\">মাগুরা গ্রুপের</a> প্রতিষ্ঠান বাংলাদেশ নিউজ অ্যান্ড এন্টারটেইনমেন্ট লিমিটেড (বিএনইএল) কর্তৃক। মালিকানাগত পৃষ্ঠপোষকতা থাকলেও সম্পাদকীয় নীতি ও সংবাদ স্বাধীনতা সম্পূর্ণরূপে স্বতন্ত্র। পত্রিকার নীতিমালায় স্পষ্টভাবে উল্লেখ রয়েছে— কোনো বাণিজ্যিক, রাজনৈতিক বা অন্য কোনো ধরনের চাপ সংবাদ নির্বাচনে বা সম্পাদকীয় সিদ্ধান্তে প্রভাব ফেলতে পারবে না।</p><p><b>সম্পাদকীয় নেতৃত্ব ও দায়িত্বশীল ব্যক্তিবর্গ</b></p><p>বর্তমানে বাংলাদেশের খবরের ভারপ্রাপ্ত সম্পাদক সৈয়দ মেজবাহ উদ্দিন। সম্পাদকমণ্ডলীর সভাপতি মোস্তফা কামাল মহীউদ্দীন এবং <a href=\"https://www.bangladesherkhabor.net/team\" target=\"_blank\">ডিজিটাল সংস্করণের</a> প্রধান <a href=\"https://www.bangladesherkhabor.net/author/12/hasnat-kadir\" target=\"_blank\">হাসনাত কাদীর</a>। তাঁদের নেতৃত্বে পত্রিকার প্রিন্ট ও ডিজিটাল উভয় সংস্করণে সংবাদ পরিবেশন, কনটেন্ট পরিকল্পনা ও প্রযুক্তিগত রূপান্তরের কার্যক্রম পরিচালিত হচ্ছে।</p><p><b>আলোর মিছিল— পাঠক ও সমাজকেন্দ্রিক সংগঠন</b></p><p>বাংলাদেশের খবর বিশ্বাস করে যে, পাঠক শুধু সংবাদগ্রাহী নয়, বরং সমাজ পরিবর্তনের এক সক্রিয় অংশীদার। এই বিশ্বাস থেকেই গড়ে তোলা হয়েছে বাংলাদেশের খবরের পাঠক-সংগঠন ‘আলোর মিছিল’। তরুণ প্রজন্ম, শিক্ষার্থী, পাঠক, শিক্ষক, সাংস্কৃতিককর্মী ও সমাজসচেতন নাগরিকদের নিয়ে গড়ে ওঠা এক আলোকিত নেটওয়ার্ক আলোর মিছিল। এর লক্ষ্য সমাজের মানুষদের মানবিক বন্ধনকে আরও গভীর করা। এই প্ল্যাটফর্মের মাধ্যমে আমরা আয়োজন করি নানা সাংস্কৃতিক ও সামাজিক কার্যক্রম— বিতর্ক ও রচনা প্রতিযোগিতা, পাঠচক্র, রক্তদান কর্মসূচি, পরিবেশ সংরক্ষণ অভিযান, শিশুদের জন্য গল্পপাঠ অনুষ্ঠান, মুক্তিযুদ্ধভিত্তিক আলোচনা, ঋতুভিত্তিক উৎসব এবং নানা জনসচেতনতা কার্যক্রম।</p><p>‘আলোর মিছিল’ তরুণদের সৃজনশীলতা ও সমাজভাবনার বিকাশে কাজ করে, তাদেরকে দায়িত্বশীল নাগরিক হিসেবে গড়ে তুলতে অনুপ্রাণিত করে। এটি একদিকে যেমন বাংলাদেশের খবরের পাঠকদের একটি বন্ধুসুলভ ও উদ্যোগী কমিউনিটি গড়ে তোলে, অন্যদিকে সমাজে আলো ছড়ানোর এক সম্মিলিত আন্দোলনে পরিণত হয়।</p><p><b>দর্শন</b></p><p>বাংলাদেশের খবর বিশ্বাস করে— সাংবাদিকতা সমাজ পরিবর্তনের এক শক্তিশালী হাতিয়ার। আমাদের রূপকল্প হলো, পাঠককে সত্য ও গভীর তথ্য দিয়ে সচেতন ও ক্ষমতাবান করে তোলা, সমাজে ন্যায়, সমতা ও মানবিকতার ভিত্তিতে ইতিবাচক পরিবর্তন ঘটানো এবং আগামী প্রজন্মের জন্য একটি জ্ঞাননির্ভর, তথ্যসমৃদ্ধ বাংলাদেশ গড়ে তোলা। আমাদের ব্রত— পেশাদারিত্ব, স্বাধীনতা, জনমুখিতা, ইতিবাচকতা, সংহতি ও সৃজনশীলতা— যার ওপর দাঁড়িয়ে আমরা প্রতিদিনের কাজ ও কনটেন্ট নীতি নির্ধারণ করি।</p><p><b>বার্তা ও বাণিজ্যিক কার্যালয়&nbsp;</b></p><p>বাংলাদেশের খবরের বার্তা ও বাণিজ্যিক কার্যালয় অবস্থিত— প্লট নং–৩১৪/এ, রোড–১৮, ব্লক–ই, বসুন্ধরা আবাসিক এলাকা, ঢাকা–১২২৯।&nbsp;</p><p><b>শেষ কথা</b></p><p>বাংলাদেশের খবর একটি দায়িত্বশীল সংবাদমাধ্যম হিসেবে জনগণের আস্থা অর্জন ও তা অটুট রাখার লক্ষ্যে প্রতিদিন নিষ্ঠার সঙ্গে কাজ করে যাচ্ছে। আমরা সংবাদে সত্য ও ন্যায়ের প্রতিষ্ঠাকে সর্বাগ্রে রাখি এবং জনগণের কণ্ঠস্বর হয়ে সমাজে ইতিবাচক পরিবর্তন আনতে প্রতিজ্ঞাবদ্ধ। আলোর পথে আমরা এগিয়ে চলেছি— পাঠকের আস্থা রক্ষা করে, সত্যের পাশে থেকে, ন্যায় ও মানবতার সঙ্গী হয়ে।</p>', '<p><b>বার্তা ও বাণিজ্যিক কার্যালয় :</b>&nbsp;প্লট নং-৩১৪/এ, রোড-১৮, ব্লক-ই, বসুন্ধরা আ/এ, ঢাকা-১২২৯। পিএবিএক্স : ৫৫০৩৬৪৫৬-৭, ৫৫০৩৬৪৫৮, ফ্যাক্স : ৮৪৩১০৯৩,&nbsp;ইমেইল : bkdigital247@gmail.com</p><p><b>প্রিন্ট সংস্করণে বিজ্ঞাপন দিতে যোগাযোগ :</b>&nbsp;০১৮৪৭-০৯১১৩১, ০১৭৩০-৭৯৩৪৭৮, ০১৮৪৭-৪২১১৫৩, ০১৩২২-৯১০৪২২, ইমেইল : bkhaboradvt2021@gmail.com</p><p><b>ডিজিটাল সংস্করণে (ওয়েবসাইট &amp; ভিডিও) বিজ্ঞাপন দিতে যোগাযোগ :</b>&nbsp;+৮৮০১৮১৩ ১৬০০৩০, +৮৮০ ১৭৪৯-১১৯৫৫৩,&nbsp; ইমেইল :&nbsp;businessbk247@gmail.com</p><p><b>সার্কুলেশন :</b>&nbsp;০১৮৪৭-৪২১১৫২</p>', '<p><br></p>', '<p><b>ব্যবহারের শর্তাবলি</b></p><p>বাংলাদেশের খবরের পাঠক, দর্শক ও ব্যবহারকারীদের আমাদের কনটেন্ট, সেবা ও ডিজিটাল প্ল্যাটফর্ম ব্যবহারের শর্তাবলিতে স্বাগত। ছাপা পত্রিকা ও <a href=\"https://epaper.bangladesherkhabor.net/\" target=\"_blank\">ইপেপারের</a> পাশাপাশি <a href=\"https://www.bangladesherkhabor.net/\" target=\"_blank\">ওয়েবসাইট (www.bangladesherkhabor.net)</a>, <a href=\"https://www.facebook.com/bkdigital247/\" target=\"_blank\">ফেসবুক</a>, <a href=\"https://www.youtube.com/@bkdigital247\" target=\"_blank\">ইউটিউব</a>, <a href=\"https://www.tiktok.com/@bkdigital247/video/7461867292977057031\" target=\"_blank\">টিকটক</a>, <a href=\"https://x.com/bkdigital247\" target=\"_blank\">এক্স</a>-সহ বিভিন্ন সামাজিক যোগাযোগমাধ্যমে বাংলাদেশের খবরের কনটেন্টে প্রবেশ করা যায়।</p><p>বাংলাদেশের খবরের কনটেন্ট, সেবা, লেখা, ছবি, ভিডিও, তথ্য বা যেকোনো উপকরণ ব্যবহার করতে হলে পাঠক-দর্শকদের অবশ্যই এই ব্যবহারের শর্তাবলি (Terms and Conditions) এবং আমাদের প্রাইভেসি পলিসি মেনে নিতে হবে। যদি কোনো ব্যবহারকারীর এসব শর্ত বা প্রাইভেসি পলিসির কোনো ধারার বিষয়ে আপত্তি বা দ্বিমত থাকে, তবে তিনি ই-মেইলের মাধ্যমে বিষয়টি আমাদের জানাতে পারেন : bkdigital247@gmail.com। তবে যেকোনো ধরনের আপত্তি বা দ্বিমত গ্রহণ বা প্রত্যাখ্যান করার পূর্ণ অধিকার দৈনিক বাংলাদেশের খবর কর্তৃপক্ষ সংরক্ষণ করে। এই শর্তাবলি লঙ্ঘিত হলে সংশ্লিষ্ট ব্যবহারকারীর অ্যাকাউন্ট স্থগিত করা বা ওয়েবসাইট ও ডিজিটাল প্ল্যাটফর্মে প্রবেশ নিষিদ্ধ করা হতে পারে।</p><p><b>মেধাস্বত্ব (ইন্টেলেকচুয়াল প্রোপার্টি) অধিকার</b></p><p>বাংলাদেশের খবরের নাম, লোগো, কপিরাইট, ট্রেডমার্ক, লেখা, ছবি, গ্রাফিক্স, ডোমেইন নাম, অডিও, ভিডিও এবং সংশ্লিষ্ট সব মেধাস্বত্ব দৈনিক বাংলাদেশের খবরের একক মালিকানাধীন। কোনো ব্যবহারকারী বাণিজ্যিক বা অবাণিজ্যিক— কোনো উদ্দেশ্যেই এসব মেধাস্বত্বের ওপর মালিকানা বা কৃতিত্ব দাবি করতে পারবেন না। পাশাপাশি দৈনিক বাংলাদেশের খবরের কনটেন্ট থেকে কোনো ধরনের ডেরিভেটিভ কাজ (পরিবর্তিত বা নতুন কাজ তৈরি) করা সম্পূর্ণ নিষিদ্ধ।</p><p><b>আমাদের সেবা ব্যবহারের নিয়ম</b></p><p>বাংলাদেশের খবরের সব সেবা কেবল আইনসম্মত ও পাঠ-দর্শনের উদ্দেশ্যে ব্যবহার করা যাবে। ওয়েবসাইট ও ডিজিটাল প্ল্যাটফর্মে প্রকাশিত অডিও-ভিডিও কনটেন্ট কেবল শোনা ও দেখার জন্য— এর বাইরে অন্য কোনো ব্যবহার অনুমোদিত নয়।</p><p>তবে বাংলাদেশের খবর পাঠকদের সামাজিক যোগাযোগমাধ্যমের প্রোফাইল, গ্রুপ বা সংশ্লিষ্ট কমিউনিটিতে আমাদের কনটেন্ট শেয়ার করতে উৎসাহিত করে। শেয়ার করার সময় কনটেন্টে কোনো ধরনের পরিবর্তন, বিকৃতি বা সম্পাদনা করা যাবে না এবং মূল সূত্র উল্লেখ করতে হবে।</p><p>ব্যবহারকারীরা কেবল ব্যক্তিগত ও অবাণিজ্যিক উদ্দেশ্যে বাংলাদেশের খবরের কনটেন্ট ব্যবহার করতে পারবেন। কোনো ধরনের বাণিজ্যিক ব্যবহার, বিক্রি, পুনঃপ্রকাশ বা আর্থিক লাভের উদ্দেশ্যে কনটেন্ট ব্যবহার সম্পূর্ণ নিষিদ্ধ।</p><p><b>কনটেন্ট অপসারণ</b></p><p>দৈনিক বাংলাদেশের খবর যেকোনো সময় তার ওয়েবসাইট, ডিজিটাল সংস্করণ বা সামাজিক যোগাযোগমাধ্যম থেকে যেকোনো কনটেন্ট অপসারণ করার অধিকার সংরক্ষণ করে। কর্তৃপক্ষের অনুরোধে ব্যবহারকারীরা তাদের নিজ নিজ ডিভাইস বা প্ল্যাটফর্ম থেকেও সংশ্লিষ্ট কনটেন্ট অপসারণে বাধ্য থাকবেন।</p><p><b>অননুমোদিত ও নিষিদ্ধ কার্যক্রম</b></p><p>ব্যবহারকারীরা কোনোভাবেই বাংলাদেশের খবরকে কোনো রাজনৈতিক দল, গোষ্ঠী, বর্ণবাদ, লিঙ্গবিদ্বেষ বা এমন কোনো কর্মকাণ্ডের সঙ্গে মেলাতে পারবেন না, যা পত্রিকার সুনাম ক্ষুণ্ন করে।</p><p>দৈনিক বাংলাদেশের খবর বা এর সঙ্গে সংশ্লিষ্ট ব্যক্তি বা প্রতিষ্ঠানের বিরুদ্ধে মানহানিকর মন্তব্য, হয়রানি, বুলিং বা অপমানজনক আচরণ নিষিদ্ধ। কোনো ধরনের আপত্তিকর, অশালীন, অশোভন বা অনৈতিক লেখা, ছবি বা মন্তব্য প্রকাশ বা আপলোড করা যাবে না। মন্তব্য বা ছবির মাধ্যমে ব্যক্তিগত আক্রমণও সম্পূর্ণভাবে নিষিদ্ধ।</p><p><b>চিহ্ন, কনটেন্ট ও ছবি শেয়ারের নিষেধাজ্ঞা</b></p><p>দৈনিক বাংলাদেশের খবরের লোগো, লেখা, ছবি বা অন্যান্য কনটেন্ট বাণিজ্যিক বা অবাণিজ্যিক— কোনো উদ্দেশ্যেই অনুমতি ছাড়া পুনঃব্যবহার, পুনঃপ্রকাশ বা নিজের নামে প্রচার করা যাবে না। বাংলাদেশের খবর কর্তৃক প্রকাশিত বা তৈরি কোনো কনটেন্ট বা ছবির কৃতিত্ব নিজের নামে নেওয়া আইনত দণ্ডনীয় অপরাধ হিসেবে গণ্য হতে পারে।</p>', '<br>', 10, NULL, NULL, '2026-01-26 19:59:10', 4);
